      {/* Edit/Add dialog */}
      {editing && (
        <Dialog open={true} onClose={() => setEditing(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{isNew ? 'Add Education' : 'Edit Education'}</DialogTitle>
