                    ))}
                  </div>
                </div>
              )
            })}
          </div>
          {/* Rejected/Withdrawn counts */}
          {((statusCounts.rejected || 0) + (statusCounts.withdrawn || 0)) > 0 && (
            <div className="flex gap-3 mt-3 text-xs text-muted-foreground">
              {statusCounts.rejected > 0 && (
                <span className="flex items-center gap-1">
